import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Initialisierung: Projekt-Setup | opencode-supermemory","description":"Lernen Sie, wie Sie /supermemory-init verwenden, um die Codebasis zu scannen und Architektur und Konventionen automatisch zu extrahieren und zu speichern.","frontmatter":{"title":"Initialisierung: Projekt-Setup | opencode-supermemory","sidebarTitle":"Initialisierung","subtitle":"Initialisierung: Projekt-Setup","description":"Lernen Sie, wie Sie /supermemory-init verwenden, um die Codebasis zu scannen und Architektur und Konventionen automatisch zu extrahieren und zu speichern.","tags":["Initialisierung","Speichergenerierung","Workflow"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"de/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"de/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),s={name:"de/supermemoryai/opencode-supermemory/start/initialization/index.md"};function a(o,e,d,l,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="projektinitialisierung-erster-eindruck" tabindex="-1">Projektinitialisierung: Erster Eindruck <a class="header-anchor" href="#projektinitialisierung-erster-eindruck" aria-label="Permalink to &quot;Projektinitialisierung: Erster Eindruck&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li><strong>Projekt schnell kennenlernen</strong>: Lassen Sie den Agenten die gesamte Codebase aktiv erforschen und verstehen, wie ein neuer Mitarbeiter.</li><li><strong>Langzeitgedächtnis aufbauen</strong>: Extrahieren Sie automatisch den Tech-Stack, die Architekturmuster und die Codierungskonventionen des Projekts und speichern Sie sie in Supermemory.</li><li><strong>Wiederholte Erklärungen vermeiden</strong>: Sie müssen nicht mehr in jeder Sitzung zu Beginn sagen &quot;Wir verwenden Bun&quot; oder &quot;Alle Komponenten müssen getestet werden&quot;.</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sind Sie bereits auf folgende Situationen gestoßen:</p><ul><li><strong>Wiederholte Arbeit</strong>: Jedes Mal, wenn Sie eine neue Sitzung starten, müssen Sie dem Agenten viel erklären, um ihm die Grundlagen des Projekts beizubringen.</li><li><strong>Kontextvergessen</strong>: Der Agent vergisst oft die projektspezifische Verzeichnisstruktur und erstellt Dateien an der falschen Stelle.</li><li><strong>Inkonsistente Konventionen</strong>: Der Codestil des Agenten schwankt; manchmal verwendet er <code>interface</code>, manchmal <code>type</code>.</li></ul><h2 id="wann-sie-diese-methode-anwenden-sollten" tabindex="-1">Wann Sie diese Methode anwenden sollten <a class="header-anchor" href="#wann-sie-diese-methode-anwenden-sollten" aria-label="Permalink to &quot;Wann Sie diese Methode anwenden sollten&quot;">​</a></h2><ul><li><strong>Unmittelbar nach der Plugin-Installation</strong>: Dies ist der erste Schritt bei der Verwendung von opencode-supermemory.</li><li><strong>Wenn Sie ein neues Projekt übernehmen</strong>: Bauen Sie schnell die Speicherdatenbank für dieses Projekt auf.</li><li><strong>Nach einer großen Refaktorisierung</strong>: Wenn sich die Projektarchitektur ändert und Sie das Wissen des Agents aktualisieren müssen.</li></ul><h2 id="🎒-vorbereitungen" tabindex="-1">🎒 Vorbereitungen <a class="header-anchor" href="#🎒-vorbereitungen" aria-label="Permalink to &quot;🎒 Vorbereitungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Vorprüfung</p><p>Stellen Sie sicher, dass Sie die Installation und Konfigurationsschritte aus <a href="./../getting-started/">Schnellstart</a> abgeschlossen haben und <code>SUPERMEMORY_API_KEY</code> korrekt festgelegt ist.</p></div><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Der Befehl <code>/supermemory-init</code> ist im Grunde kein Binärprogramm, sondern ein <strong>sorgfältig gestalteter Prompt</strong> (Eingabeaufforderung).</p><p>Wenn Sie diesen Befehl ausführen, sendet er dem Agenten einen detaillierten &quot;Onboarding-Leitfaden&quot;, der den Agenten anweist:</p><ol><li><strong>Tiefgehende Recherche</strong>: Aktiv lesen Sie <code>README.md</code>, <code>package.json</code>, Git-Commit-Verläufe usw.</li><li><strong>Strukturierte Analyse</strong>: Erkennen Sie den Tech-Stack, die Architekturmuster und die impliziten Konventionen des Projekts.</li><li><strong>Persistente Speicherung</strong>: Verwenden Sie das <code>supermemory</code>-Tool, um diese Erkenntnisse in der Cloud-Datenbank zu speichern.</li></ol><div class="info custom-block"><p class="custom-block-title">Speicherumfang</p><p>Der Initialisierungsprozess unterscheidet zwischen zwei Arten von Speichern:</p><ul><li><strong>Project Scope</strong>: Nur für das aktuelle Projekt wirksam (z. B. Build-Befehle, Verzeichnisstruktur).</li><li><strong>User Scope</strong>: Für alle Ihre Projekte wirksam (z. B. Ihr bevorzugter Codestil).</li></ul></div><h2 id="fuhren-sie-es-mit-mir-aus" tabindex="-1">Führen Sie es mit mir aus <a class="header-anchor" href="#fuhren-sie-es-mit-mir-aus" aria-label="Permalink to &quot;Führen Sie es mit mir aus&quot;">​</a></h2><h3 id="schritt-1-initialisierungsbefehl-ausfuhren" tabindex="-1">Schritt 1: Initialisierungsbefehl ausführen <a class="header-anchor" href="#schritt-1-initialisierungsbefehl-ausfuhren" aria-label="Permalink to &quot;Schritt 1: Initialisierungsbefehl ausführen&quot;">​</a></h3><p>Geben Sie im OpenCode-Eingabefeld den folgenden Befehl ein und senden Sie ihn:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>Warum</strong> Dies lädt den vordefinierten Prompt und startet den Erkundungsmodus des Agenten.</p><p><strong>Was Sie sehen sollten</strong> Der Agent beginnt zu antworten, signalisiert, dass er die Aufgabe verstanden hat, und plant die Recherche-Schritte. Er könnte sagen: &quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="schritt-2-beobachten-sie-den-erkundungsprozess-des-agenten" tabindex="-1">Schritt 2: Beobachten Sie den Erkundungsprozess des Agenten <a class="header-anchor" href="#schritt-2-beobachten-sie-den-erkundungsprozess-des-agenten" aria-label="Permalink to &quot;Schritt 2: Beobachten Sie den Erkundungsprozess des Agenten&quot;">​</a></h3><p>Der Agent führt automatisch eine Reihe von Operationen aus; Sie müssen nur zusehen. Normalerweise tut er Folgendes:</p><ol><li><strong>Konfigurationsdateien lesen</strong>: Lesen Sie <code>package.json</code>, <code>tsconfig.json</code> usw., um den Tech-Stack zu verstehen.</li><li><strong>Git-Verlauf anzeigen</strong>: Führen Sie <code>git log</code> aus, um Commit-Konventionen und aktive Mitwirkende zu verstehen.</li><li><strong>Verzeichnisstruktur erkunden</strong>: Verwenden Sie <code>ls</code> oder <code>list_files</code>, um das Projektlayout anzuzeigen.</li></ol><p><strong>Beispielausgabe</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Verbrauchshinweis</p><p>Dieser Prozess ist eine tiefgehende Recherche und kann viele Tokens verbrauchen (normalerweise 50+ Tool-Aufrufe). Haben Sie Geduld, bis der Agent den Abschluss meldet.</p></div><h3 id="schritt-3-generierte-speicher-verifizieren" tabindex="-1">Schritt 3: Generierte Speicher verifizieren <a class="header-anchor" href="#schritt-3-generierte-speicher-verifizieren" aria-label="Permalink to &quot;Schritt 3: Generierte Speicher verifizieren&quot;">​</a></h3><p>Wenn der Agent meldet, dass die Initialisierung abgeschlossen ist, können Sie überprüfen, was er genau behalten hat. Geben Sie ein:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> List</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> current</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memories</span></span></code></pre></div><p>Oder rufen Sie das Tool direkt auf (wenn Sie die Rohdaten sehen möchten):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong> Der Agent listet eine Reihe strukturierter Speicher auf, wie zum Beispiel:</p><table tabindex="0"><thead><tr><th>Typ</th><th>Inhaltsbeispiel</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="schritt-4-fehlende-erganzung-optional" tabindex="-1">Schritt 4: Fehlende Ergänzung (optional) <a class="header-anchor" href="#schritt-4-fehlende-erganzung-optional" aria-label="Permalink to &quot;Schritt 4: Fehlende Ergänzung (optional)&quot;">​</a></h3><p>Wenn der Agent einige wichtige Informationen verpasst hat (z. B. eine spezielle Regel, die nur mündlich vereinbart wurde), können Sie sie manuell ergänzen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bitte merken Sie sich: In diesem Projekt muss die Datumsbearbeitung unbedingt die Bibliothek dayjs verwenden; die Verwendung von nativem Date ist verboten.</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong> Der Agent bestätigt und ruft <code>supermemory(mode: &quot;add&quot;)</code> auf, um diese neue Regel zu speichern.</p><h2 id="prufpunkt-✅" tabindex="-1">Prüfpunkt ✅ <a class="header-anchor" href="#prufpunkt-✅" aria-label="Permalink to &quot;Prüfpunkt ✅&quot;">​</a></h2><ul><li>[ ] Führt der Agent nach dem Ausführen von <code>/supermemory-init</code> automatisch die Erkundungsaufgaben durch?</li><li>[ ] Können Sie mit dem <code>list</code>-Befehl die neu generierten Speicher aufrufen?</li><li>[ ] Reflektiert der Speicherinhalt die tatsächliche Situation des aktuellen Projekts genau?</li></ul><h2 id="fallstricke" tabindex="-1">Fallstricke <a class="header-anchor" href="#fallstricke" aria-label="Permalink to &quot;Fallstricke&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Nicht zu oft ausführen</p><p>Die Initialisierung ist ein zeitaufwendiger und token-intensiver Prozess. Normalerweise muss jeder Projekt nur einmal ausgeführt werden. Nur wenn das Projekt große Änderungen erfährt, müssen Sie es erneut ausführen.</p></div><div class="danger custom-block"><p class="custom-block-title">Datenschutz</p><p>Obwohl das Plugin den Inhalt von <code>&lt;private&gt;</code>-Tags automatisch maskiert, liest der Agent während der Initialisierung viele Dateien. Stellen Sie sicher, dass Ihre Codebase keine fest codierten geheimen Schlüssel (z. B. AWS Secret Key) enthält, da sie sonst als &quot;Projektkonfiguration&quot; im Speicher abgelegt werden könnten.</p></div><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>Durch <code>/supermemory-init</code> haben wir den Übergang vom &quot;Fremden&quot; zum &quot;erfahrenen Mitarbeiter&quot; vollzogen. Jetzt hat der Agent die Kernarchitektur und Konventionen des Projekts gespeichert. In den kommenden Codierungsaufgaben wird er diesen Kontext automatisch nutzen, um Ihnen präzisere Unterstützung zu bieten.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../core/context-injection/">Automatischer Kontextinjektionsmechanismus</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie der Agent beim Sitzungsstart an diese Speicher &quot;denkt&quot;.</li><li>Wie Sie durch Schlüsselwörter spezifische Speicherrückrufe auslösen.</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>: Definiert den genauen Prompt-Inhalt des Befehls <code>/supermemory-init</code> und leitet den Agenten an, wie Recherche und Speicherung durchzuführen werden.</li></ul></details>`,50)])])}const p=n(s,[["render",a]]);export{g as __pageData,p as default};
